class Solution:
    def almostPalindromic(self, s):
        # Direct definition check: for every substring and every possible
        # single removal position inside it, test the literal remainder for
        # being a palindrome. Cubic-ish and only used on small inputs, but
        # independent of the table-based optimal approach.
        n = len(s)
        best = 0
        for i in range(n):
            for j in range(i, n):
                sub = s[i:j + 1]
                length = len(sub)
                for p in range(length):
                    remainder = sub[:p] + sub[p + 1:]
                    if remainder == remainder[::-1]:
                        if length > best:
                            best = length
                        break
        return best

