class Solution:
    def almostPalindromic(self, s: str) -> int:
        n = len(s)
        if n <= 1:
            return n
        NEG = -1
        # state[i][j] for i < j: -1 means s[i..j] is already a palindrome;
        # otherwise the number of matching outer layers before the first
        # mismatch when scanning from the ends of [i, j] inward.
        state = [[NEG] * n for _ in range(n)]
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if s[i] != s[j]:
                    state[i][j] = 0
                elif length == 2:
                    state[i][j] = NEG
                else:
                    inner = state[i + 1][j - 1]
                    state[i][j] = NEG if inner == NEG else inner + 1

        def is_pal(a, b):
            if a >= b:
                return True
            return state[a][b] == NEG

        best = 1
        for i in range(n):
            for j in range(i + 1, n):
                st = state[i][j]
                length = j - i + 1
                if st == NEG:
                    if length > best:
                        best = length
                    continue
                k = st
                li, lj = i + k, j - k
                if is_pal(li + 1, lj) or is_pal(li, lj - 1):
                    if length > best:
                        best = length
        return best

