var almostPalindromic = function(s) {
    const n = s.length;
    if (n <= 1) return n;
    const NEG = -1;
    const state = new Int32Array(n * n).fill(NEG);
    for (let length = 2; length <= n; length++) {
        for (let i = 0; i <= n - length; i++) {
            const j = i + length - 1;
            if (s[i] !== s[j]) {
                state[i * n + j] = 0;
            } else if (length === 2) {
                state[i * n + j] = NEG;
            } else {
                const inner = state[(i + 1) * n + (j - 1)];
                state[i * n + j] = inner === NEG ? NEG : inner + 1;
            }
        }
    }
    const isPal = (a, b) => {
        if (a >= b) return true;
        return state[a * n + b] === NEG;
    };
    let best = 1;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const st = state[i * n + j];
            const length = j - i + 1;
            if (st === NEG) {
                if (length > best) best = length;
                continue;
            }
            const k = st;
            const li = i + k, lj = j - k;
            if (isPal(li + 1, lj) || isPal(li, lj - 1)) {
                if (length > best) best = length;
            }
        }
    }
    return best;
};
